// memberOnTeam reports whether userID is already on team t (so the add-member
// select omits them).
func memberOnTeam(t TeamView, userID uuid.UUID) bool {
	for _, m := range t.Members {
		if m.UserID == userID {
			return true
		}
	}
	return false
}

